-- Gate 6 seed for RA weekly management project details.
-- Scope: public.ll_weekly_reports / public.ll_weekly_assets / public.ll_weekly_projects only.
-- This preserves source rows in row_json so the UI can move away from static JSON fallback.

do $$
declare
  v_report_id uuid := '00000000-0000-0000-0000-000000260427';
begin
    id, week_key, organization, report_year, report_month, report_week,
    source_file_name, source_sha256, source_text, report_json
  ) values (
    v_report_id, '2026-04-5', '사업그룹4파트', 2026, 4, 5,
    'RA부문_사업그룹4파트_주간업무자료(안)_260427_취합.docx', 'fe542946536dee15dd7ae41f018e35b0c0dacb8b810d1d564e614b9be7fe441b', null,
    '{"sourceDocumentName":"RA부문_사업그룹4파트_주간업무자료(안)_260427_취합.docx","reportDate":"2026-04-06","summary":{"assetCount":20,"totalGrossAreaPy":537080,"riskAssetCount":5,"leaseUpIssueCount":6,"fullyLeasedCount":6},"seed":"gate6_weekly_project_details_seed"}'::jsonb
  )
  on conflict (week_key, organization) do update set
    source_file_name = excluded.source_file_name,
    source_sha256 = excluded.source_sha256,
    report_json = excluded.report_json,
    updated_at = now()
  returning id into v_report_id;

  delete from public.ll_weekly_assets where report_id = v_report_id;
  delete from public.ll_weekly_projects where report_id = v_report_id;


end $$;
